alter table public.agent_task_events add constraint agent_task_events_event_type_check CHECK ((event_type = ANY (ARRAY['comment'::text, 'instruction'::text, 'property_changed'::text, 'status_changed'::text, 'output_created'::text, 'approval_event'::text, 'system_event'::text])));
alter table public.agent_task_events add constraint agent_task_events_pkey PRIMARY KEY (id);
alter table public.agent_task_events add constraint agent_task_events_title_check CHECK ((length(btrim(title)) > 0));
